import { initializeApp, getApps } from 'firebase/app';
import { getAuth, connectAuthEmulator } from 'firebase/auth';
import { getFirestore, connectFirestoreEmulator } from 'firebase/firestore';
import { getStorage } from 'firebase/storage';

const firebaseConfig = {
  apiKey: process.env.NEXT_PUBLIC_FIREBASE_API_KEY,
  authDomain: process.env.NEXT_PUBLIC_FIREBASE_AUTH_DOMAIN,
  projectId: process.env.NEXT_PUBLIC_FIREBASE_PROJECT_ID,
  storageBucket: process.env.NEXT_PUBLIC_FIREBASE_STORAGE_BUCKET,
  messagingSenderId: process.env.NEXT_PUBLIC_FIREBASE_MESSAGING_SENDER_ID,
  appId: process.env.NEXT_PUBLIC_FIREBASE_APP_ID,
};

const app = getApps().length === 0 ? initializeApp(firebaseConfig) : getApps()[0];

export const auth = getAuth(app);
export const db = getFirestore(app);
export const storage = getStorage(app);

// ── Connect to local emulators in development ───────────────────────────────
// The firebase emulator is running on localhost:9099 (auth) and localhost:8080 (firestore).
// This gives us instant Firestore reads/writes with local security rules.
if (process.env.NODE_ENV === 'development' && typeof window !== 'undefined') {
  // Guards prevent "already initialized" error on hot-reload
  try { connectAuthEmulator(auth, 'http://localhost:9099', { disableWarnings: true }); } catch (_) { }
  try { connectFirestoreEmulator(db, 'localhost', 8080); } catch (_) { }
}

export default app;
